import { useState } from "react";
import { useSpeechRecognition, useTTS } from "../../hooks/useSpeech";

export default function SpeakingSection({ speaking: data, onDone, done }) {
  console.log(done)
  const { speak, speaking } = useTTS();
  const { listening, transcript, error, startListening, stopListening, reset } =
    useSpeechRecognition();
  const [recordings, setRecordings] = useState([]);
  const [showTips, setShowTips] = useState(false);

  function handleRecord() {
    if (listening) {
      stopListening();
    } else {
      reset();
      startListening();
    }
  }

  function saveRecording() {
    if (transcript.trim()) {
      setRecordings((r) => [
        ...r,
        { text: transcript, time: new Date().toLocaleTimeString() },
      ]);
      reset();
    }
  }

  return (
    <div className="fade-in">
      <div className="bg-gradient-to-br from-purple-50 to-pink-50 border-2 border-purple-100 rounded-2xl p-5 mb-4">
        <h3 className="font-bold text-purple-900 mb-1">🎤 Speaking Topic</h3>
        <p className="text-base font-extrabold text-slate-800 mb-3">
          "{data.topic}"
        </p>
        <p className="text-sm text-slate-600 leading-relaxed">{data.prompt}</p>
      </div>

      {/* Example */}
      <div className="bg-white border border-slate-200 rounded-xl p-4 mb-4">
        <div className="flex items-start gap-3">
          <button
            onClick={() => speak(data.example)}
            className={`flex-shrink-0 w-9 h-9 flex items-center justify-center rounded-xl border-2 transition-all
              ${speaking ? "bg-blue-900 border-blue-900 text-white" : "bg-slate-50 border-slate-200 text-slate-500 hover:bg-blue-900 hover:border-blue-900 hover:text-white"}`}
          >
            🔊
          </button>
          <div>
            <p className="text-xs font-bold text-slate-400 mb-1">
              Example Answer:
            </p>
            <p className="text-sm text-slate-700 italic">"{data.example}"</p>
          </div>
        </div>
      </div>

      {/* Tips */}
      <button
        onClick={() => setShowTips((s) => !s)}
        className="text-sm text-indigo-700 font-bold hover:underline mb-3 flex items-center gap-1"
      >
        💡 {showTips ? "Hide Tips" : "Show Speaking Tips"}
      </button>
      {showTips && (
        <div className="bg-yellow-50 border border-yellow-200 rounded-xl p-4 mb-4 fade-in">
          <ul className="space-y-1.5">
            {data.tips.map((tip, i) => (
              <li
                key={i}
                className="text-sm text-yellow-800 font-bold flex items-start gap-2"
              >
                <span>✦</span>
                <span>{tip}</span>
              </li>
            ))}
          </ul>
        </div>
      )}

      {/* Mic */}
      <div className="text-center bg-white border-2 border-slate-200 rounded-2xl p-6 mb-4">
        <button
          onClick={handleRecord}
          className={`w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-3 text-3xl transition-all duration-200 border-4 shadow-lg
            ${
              listening
                ? "bg-red-500 border-red-300 scale-110 pulse-ring animate-pulse"
                : "bg-blue-900 border-blue-700 hover:scale-105"
            }`}
        >
          🎤
        </button>
        <p className="text-sm font-bold text-slate-700">
          {listening
            ? "🔴 Recording... Speak now!"
            : "Click to start recording"}
        </p>
        {error && <p className="text-xs text-red-500 mt-1">{error}</p>}

        {transcript && (
          <div className="mt-4 bg-slate-50 border border-slate-200 rounded-xl p-3 fade-in text-left">
            <p className="text-xs font-bold text-slate-400 mb-1">
              Your answer:
            </p>
            <p className="text-sm text-slate-800 font-bold">"{transcript}"</p>
            <div className="flex gap-2 mt-2">
              <button
                onClick={saveRecording}
                className="text-xs bg-green-700 text-white px-4 py-1.5 rounded-lg font-bold hover:bg-green-600 transition-all"
              >
                Save ✓
              </button>
              <button
                onClick={reset}
                className="text-xs bg-slate-200 text-slate-600 px-4 py-1.5 rounded-lg font-bold hover:bg-slate-300 transition-all"
              >
                Clear
              </button>
            </div>
          </div>
        )}
      </div>

      {/* Saved recordings */}
      {recordings.length > 0 && (
        <div className="mb-4">
          <p className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">
            Your Recordings
          </p>
          {recordings.map((r, i) => (
            <div
              key={i}
              className="bg-white border border-slate-200 rounded-xl p-3 mb-2 flex items-center gap-3"
            >
              <span className="text-lg">🎙️</span>
              <div className="flex-1">
                <p className="text-sm text-slate-800 font-bold">"{r.text}"</p>
                <p className="text-xs text-slate-400">{r.time}</p>
              </div>
            </div>
          ))}
        </div>
      )}

      {!done ? (
        <div className="flex justify-end">
          <button
            onClick={onDone}
            className="bg-blue-900 hover:bg-blue-800 text-white font-bold px-8 py-3 rounded-xl text-sm transition-all hover:-translate-y-0.5"
          >
            Mark as Done ✓
          </button>
        </div>
      ) : (
        <p className="text-right text-green-700 font-bold text-sm mt-2">
          ✓ Speaking completed!
        </p>
      )}
    </div>
  );
}
